class Solution {
 public long repairCars(int[] ranks, int cars) {
     Arrays.sort(ranks);
     long left = 0, right = (long) ranks[ranks.length - 1] * cars * cars;
     while (left < right) {
         long mid = left + (right - left) / 2;
         long count = 0;
         for (int rank : ranks) {
             count += (long) Math.sqrt(mid / rank);
         }
         if (count < cars) {
             left = mid + 1;
         } else {
             right = mid;
         }
     }
     return left;
 }
}
```
